CREATE OR REPLACE FUNCTION public.advance_cadence_state(p_matricula text, p_template_name text, p_phone_number_id text, p_wamid text DEFAULT NULL::text, p_meta jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_cliente        clientes_cobranca_setembro%ROWTYPE;
  v_slot_config    cadence_slot_config%ROWTYPE;
  v_log_inserted   bigint;
  v_new_fase       text;
  v_new_dia        int;
  v_new_slots      int;
  v_promoted       boolean := false;
  v_today_brt      date := (now() AT TIME ZONE 'America/Sao_Paulo')::date;
  v_next_envio     timestamptz;
BEGIN
  SELECT * INTO v_cliente
  FROM clientes_cobranca_setembro
  WHERE matricula = p_matricula
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'matricula_not_found', 'matricula', p_matricula);
  END IF;

  IF v_cliente.cadence_fase IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'cliente_sem_cadencia', 'matricula', p_matricula);
  END IF;

  SELECT * INTO v_slot_config
  FROM cadence_slot_config
  WHERE fase = v_cliente.cadence_fase
    AND dia_ciclo = v_cliente.cadence_dia_ciclo
    AND slot = COALESCE(v_cliente.slots_enviados_hoje, 0) + 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'slot_config_not_found',
      'fase', v_cliente.cadence_fase,
      'dia_ciclo', v_cliente.cadence_dia_ciclo,
      'slot_expected', COALESCE(v_cliente.slots_enviados_hoje, 0) + 1
    );
  END IF;

  IF p_wamid IS NOT NULL THEN
    INSERT INTO message_log (
      matricula, unit_id, phone_number_id, to_whatsapp,
      template_name, wa_message_id,
      cadence_fase, cadence_dia_ciclo, cadence_slot,
      sent_at, status, raw_response
    )
    VALUES (
      v_cliente.matricula, v_cliente.unit_id, p_phone_number_id, v_cliente.whatsapp,
      p_template_name, p_wamid,
      v_slot_config.fase, v_slot_config.dia_ciclo, v_slot_config.slot,
      now(), 'sent', p_meta
    )
    ON CONFLICT (wa_message_id) WHERE wa_message_id IS NOT NULL
    DO NOTHING
    RETURNING id INTO v_log_inserted;

    IF v_log_inserted IS NULL THEN
      RETURN jsonb_build_object(
        'ok', true,
        'idempotent_replay', true,
        'matricula', p_matricula,
        'wa_message_id', p_wamid
      );
    END IF;
  ELSE
    INSERT INTO message_log (
      matricula, unit_id, phone_number_id, to_whatsapp,
      template_name, wa_message_id,
      cadence_fase, cadence_dia_ciclo, cadence_slot,
      sent_at, status, raw_response
    )
    VALUES (
      v_cliente.matricula, v_cliente.unit_id, p_phone_number_id, v_cliente.whatsapp,
      p_template_name, NULL,
      v_slot_config.fase, v_slot_config.dia_ciclo, v_slot_config.slot,
      now(), 'sent', p_meta
    )
    RETURNING id INTO v_log_inserted;
  END IF;

  v_new_slots := COALESCE(v_cliente.slots_enviados_hoje, 0) + 1;
  v_new_fase  := v_cliente.cadence_fase;
  v_new_dia   := v_cliente.cadence_dia_ciclo;

  IF v_new_slots >= v_slot_config.envios_no_dia THEN
    v_new_slots := 0;
    v_promoted := true;

    IF v_cliente.cadence_fase = '00' THEN
      v_new_fase := '01';
      v_new_dia  := 1;
    ELSIF v_cliente.cadence_fase = '01' THEN
      IF v_cliente.cadence_dia_ciclo >= 5 THEN
        v_new_fase := '02';
        v_new_dia  := 1;
      ELSE
        v_new_dia := v_cliente.cadence_dia_ciclo + 1;
      END IF;
    ELSE
      v_promoted := false;
      v_new_slots := COALESCE(v_cliente.slots_enviados_hoje, 0) + 1;
    END IF;
  END IF;

  -- Ao promover dia/fase: defer pra amanha 09:00 BRT (evita borda do dia).
  -- Intra-dia: janela MÍNIMA de 3h ate o proximo disparo (decisao 2026-05-20).
  IF v_promoted THEN
    v_next_envio := ((v_today_brt + 1) + time '09:00:00') AT TIME ZONE 'America/Sao_Paulo';
  ELSE
    v_next_envio := now() + interval '3 hours';
  END IF;

  UPDATE clientes_cobranca_setembro
  SET
    cadence_fase             = v_new_fase,
    cadence_dia_ciclo        = v_new_dia,
    cadence_slot             = v_slot_config.slot,
    cadence_ultimo_template  = p_template_name,
    slots_enviados_hoje      = v_new_slots,
    slots_enviados_hoje_data = v_today_brt,
    cadence_proximo_envio_at = v_next_envio
  WHERE matricula = p_matricula;

  RETURN jsonb_build_object(
    'ok', true,
    'matricula', p_matricula,
    'log_id', v_log_inserted,
    'slot_sent', v_slot_config.slot,
    'fase_before', v_cliente.cadence_fase,
    'dia_before', v_cliente.cadence_dia_ciclo,
    'fase_after', v_new_fase,
    'dia_after', v_new_dia,
    'slots_hoje_after', v_new_slots,
    'promoted', v_promoted,
    'next_envio_at', v_next_envio
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.auto_reconcile_orfaos(p_source text DEFAULT NULL::text, p_max integer DEFAULT 1000, p_days_back integer DEFAULT 30)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_orfao RECORD;
  v_resolve jsonb;
  v_recon   jsonb;
  v_resolved int := 0;
  v_reconciled int := 0;
  v_unresolved int := 0;
  v_errors int := 0;
  v_unresolved_ids bigint[] := ARRAY[]::bigint[];
  v_error_details jsonb := '[]'::jsonb;
BEGIN
  FOR v_orfao IN
    SELECT id, source, gateway_correlation_id, payer_phone
    FROM pagamentos_orfaos
    WHERE reconciliado = false
      AND (p_source IS NULL OR source = p_source)
      AND created_at >= NOW() - (p_days_back || ' days')::interval
    ORDER BY created_at ASC
    LIMIT p_max
  LOOP
    BEGIN
      v_resolve := public.resolve_orfao_matricula(
        v_orfao.gateway_correlation_id,
        v_orfao.payer_phone
      );

      IF (v_resolve->>'ok')::boolean THEN
        v_resolved := v_resolved + 1;
        v_recon := public.reconcile_orfao(
          p_orfao_id := v_orfao.id,
          p_matricula := v_resolve->>'matricula'
        );
        IF (v_recon->>'ok')::boolean THEN
          v_reconciled := v_reconciled + 1;
        ELSE
          v_errors := v_errors + 1;
          v_error_details := v_error_details || jsonb_build_object(
            'orfao_id', v_orfao.id, 'stage', 'reconcile', 'error', v_recon
          );
        END IF;
      ELSE
        v_unresolved := v_unresolved + 1;
        v_unresolved_ids := array_append(v_unresolved_ids, v_orfao.id);
      END IF;
    EXCEPTION WHEN OTHERS THEN
      v_errors := v_errors + 1;
      v_error_details := v_error_details || jsonb_build_object(
        'orfao_id', v_orfao.id, 'stage', 'exception', 'error', SQLERRM
      );
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'source_filter', p_source,
    'resolved', v_resolved,
    'reconciled', v_reconciled,
    'unresolved', v_unresolved,
    'errors', v_errors,
    'unresolved_orfao_ids', v_unresolved_ids,
    'error_details', v_error_details
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.batch_update_disparo_outcomes(p_outcomes jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_outcome jsonb;
  v_mat text;
  v_kind text;
  v_now timestamptz := now();
  v_full int := 0;
  v_light int := 0;
  v_errado int := 0;
  v_skipped int := 0;
BEGIN
  IF p_outcomes IS NULL OR jsonb_array_length(p_outcomes) = 0 THEN
    RETURN jsonb_build_object('ok', true, 'full', 0, 'light', 0, 'errado', 0, 'total', 0);
  END IF;

  FOR v_outcome IN SELECT * FROM jsonb_array_elements(p_outcomes) LOOP
    v_mat := v_outcome->>'matricula';
    v_kind := v_outcome->>'outcome';
    IF v_mat IS NULL OR v_mat = '' THEN
      v_skipped := v_skipped + 1;
      CONTINUE;
    END IF;

    IF v_kind = 'full' THEN
      UPDATE clientes_cobranca_setembro SET
        disparos = COALESCE(disparos, 0) + 1,
        disparos_equipe = COALESCE(disparos_equipe, 0) + 1,
        "disparado com sucesso" = true,
        data_ultimo_disparo = v_now
      WHERE matricula = v_mat;
      v_full := v_full + 1;

    ELSIF v_kind = 'light' THEN
      UPDATE clientes_cobranca_setembro SET
        disparos = COALESCE(disparos, 0) + 1,
        data_ultimo_disparo = v_now
      WHERE matricula = v_mat;
      v_light := v_light + 1;

    ELSIF v_kind = 'errado' THEN
      UPDATE clientes_cobranca_setembro SET status = 'whatsapp errado' WHERE matricula = v_mat;
      v_errado := v_errado + 1;

    ELSE
      v_skipped := v_skipped + 1;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'full', v_full,
    'light', v_light,
    'errado', v_errado,
    'skipped', v_skipped,
    'total', v_full + v_light + v_errado
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.call_reconcile_function(p_function_slug text, p_hours_back integer DEFAULT 48)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_internal_key text;
  v_url text;
  v_request_id bigint;
BEGIN
  SELECT value INTO v_internal_key
  FROM public.app_internal_config
  WHERE key = 'NOTIFY_ORPHAN_INTERNAL_KEY';

  IF v_internal_key IS NULL THEN
    RAISE WARNING 'NOTIFY_ORPHAN_INTERNAL_KEY não configurada — pulando %', p_function_slug;
    RETURN NULL;
  END IF;

  v_url := format(
    'https://ubwcxktaruxqacxltovq.supabase.co/functions/v1/%s?hours_back=%s',
    p_function_slug, p_hours_back
  );

  SELECT net.http_post(
    url := v_url,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-internal-key', v_internal_key
    ),
    body := '{}'::jsonb,
    timeout_milliseconds := 240000  -- 4 min
  ) INTO v_request_id;

  RETURN v_request_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.can_access_unit(unit_code_param text)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  current_user_id UUID;
  target_unit_id UUID;
  is_admin BOOLEAN;
BEGIN
  -- Obter o ID do usuário autenticado
  current_user_id := auth.uid();

  -- Se não há usuário autenticado, negar acesso
  IF current_user_id IS NULL THEN
    RETURN FALSE;
  END IF;

  -- Buscar o ID da unidade pelo código
  SELECT id INTO target_unit_id
  FROM public.units
  WHERE code = unit_code_param;

  -- Se a unidade não existe, negar acesso
  IF target_unit_id IS NULL THEN
    RETURN FALSE;
  END IF;

  -- Verificar se o usuário é admin
  SELECT EXISTS (
    SELECT 1 
    FROM public.user_roles 
    WHERE user_id = current_user_id 
    AND role = 'admin'
  ) INTO is_admin;

  -- Se é admin, tem acesso
  IF is_admin THEN
    RETURN TRUE;
  END IF;

  -- Para usuários não-admin, verificar se tem permissão ativa
  RETURN EXISTS (
    SELECT 1
    FROM public.user_unit_permissions
    WHERE user_id = current_user_id
    AND unit_id = target_unit_id
    AND is_active = TRUE
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.chat_notify_handoff()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  origin text;
  secret text;
begin
  select value into origin from public.chat_config where key = 'app_origin';
  select value into secret from public.chat_config where key = 'cron_secret';

  if new.routing = 'queued'
     and (old.routing is distinct from new.routing)
     and origin is not null and origin <> '' then
    perform net.http_post(
      url := origin || '/api/internal/push/notify',
      headers := jsonb_build_object(
        'content-type', 'application/json',
        'x-cron-secret', coalesce(secret, '')
      ),
      body := jsonb_build_object(
        'conversation_id', new.id,
        'unit_id',         new.unit_id,
        'reason',          new.handoff_reason
      )
    );
  end if;
  return new;
end$function$

CREATE OR REPLACE FUNCTION public.chat_record_outbound_message(p_phone_number_id text, p_to text, p_type text, p_payload jsonb, p_wa_message_id text DEFAULT NULL::text, p_status text DEFAULT 'sent'::text, p_sent_by text DEFAULT 'ai'::text, p_contact_name text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
declare
  v_phone_row uuid; v_unit uuid; v_contact uuid; v_conv uuid; v_msg uuid;
begin
  if p_to is null or p_type is null or p_payload is null then
    raise exception 'p_to, p_type e p_payload são obrigatórios';
  end if;

  select cpn.id, w.unit_id into v_phone_row, v_unit
  from public.chat_phone_numbers cpn
  join public.wabas w on w.id = cpn.waba_id
  where cpn.phone_number_id = p_phone_number_id;

  if v_phone_row is null then
    raise exception 'phone_number_id % não cadastrado em chat_phone_numbers', p_phone_number_id;
  end if;

  insert into public.contacts as c (unit_id, wa_id, name)
  values (v_unit, p_to, nullif(p_contact_name, ''))
  on conflict (unit_id, wa_id) do update set name = coalesce(c.name, excluded.name)
  returning c.id into v_contact;

  select id into v_conv from public.conversations
  where contact_id = v_contact and status = 'open' limit 1;

  if v_conv is null then
    begin
      insert into public.conversations (unit_id, contact_id, phone_number_id)
      values (v_unit, v_contact, v_phone_row) returning id into v_conv;
    exception when unique_violation then
      select id into v_conv from public.conversations
      where contact_id = v_contact and status = 'open' limit 1;
    end;
  end if;

  insert into public.messages (conversation_id, wa_message_id, direction, type, payload, sent_by, status)
  values (
    v_conv, nullif(p_wa_message_id, ''), 'out', p_type, p_payload,
    coalesce(nullif(p_sent_by, ''), 'ai')::chat_sender_kind,
    coalesce(nullif(p_status, ''), 'sent')::chat_message_status
  )
  on conflict (wa_message_id) do nothing
  returning id into v_msg;

  return jsonb_build_object('conversation_id', v_conv, 'message_id', v_msg, 'inserted', v_msg is not null);
end;
$function$

CREATE OR REPLACE FUNCTION public.chat_stamp_conversation_transition()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  if new.routing = 'queued'::public.chat_routing_state
     and old.routing is distinct from new.routing
     and new.queued_at is null then
    new.queued_at := now();
  end if;

  if new.assigned_operator_id is distinct from old.assigned_operator_id
     and new.assigned_operator_id is not null then
    new.assigned_at := now();
  end if;

  if new.status = 'closed'::public.chat_conversation_status
     and old.status is distinct from new.status
     and new.closed_at is null then
    new.closed_at := now();
  end if;

  return new;
end;
$function$

CREATE OR REPLACE FUNCTION public.create_emergency_admin(admin_email text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  admin_user_id UUID;
  result_message TEXT;
BEGIN
  -- Find user by email
  SELECT id INTO admin_user_id 
  FROM auth.users 
  WHERE email = admin_email;

  IF admin_user_id IS NULL THEN
    RETURN 'User not found with email: ' || admin_email;
  END IF;

  -- Insert admin role if not exists
  INSERT INTO public.user_roles (user_id, role)
  VALUES (admin_user_id, 'admin'::app_role)
  ON CONFLICT (user_id, role) DO NOTHING;

  -- Also insert collections_agent role
  INSERT INTO public.user_roles (user_id, role)
  VALUES (admin_user_id, 'collections_agent'::app_role)
  ON CONFLICT (user_id, role) DO NOTHING;

  RETURN 'Admin access granted to: ' || admin_email;
END;
$function$

CREATE OR REPLACE FUNCTION public.ensure_admin_permissions(user_email text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  user_uuid uuid;
BEGIN
  SELECT id INTO user_uuid FROM auth.users WHERE email = user_email;

  IF user_uuid IS NULL THEN
    RAISE EXCEPTION 'Usuário com email % não encontrado', user_email;
  END IF;

  -- Inserir role de admin se não existir
  INSERT INTO public.user_roles (user_id, role, created_at)
  VALUES (user_uuid, 'admin', now())
  ON CONFLICT (user_id, role) DO NOTHING;

  -- Garantir permissões admin em todas as unidades (se a tabela existir)
  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'user_unit_permissions') THEN
    INSERT INTO public.user_unit_permissions (user_id, unit_id, permission, granted_at)
    SELECT user_uuid, u.id, 'admin', now()
    FROM public.units u
    WHERE NOT EXISTS (
      SELECT 1 FROM public.user_unit_permissions uup
      WHERE uup.user_id = user_uuid AND uup.unit_id = u.id AND uup.permission = 'admin'
    );
  END IF;

  RETURN true;
END;
$function$

CREATE OR REPLACE FUNCTION public.grant_multiple_permissions(_user_email text, _unit_code text, _permissions text[])
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _permission text;
  _result text;
  _success_count int := 0;
  _error_count int := 0;
BEGIN
  FOREACH _permission IN ARRAY _permissions
  LOOP
    BEGIN
      SELECT public.grant_unit_permission(_user_email, _unit_code, _permission::permission_type) INTO _result;

      IF _result LIKE 'Permissão concedida%' THEN
        _success_count := _success_count + 1;
      ELSE
        _error_count := _error_count + 1;
        RAISE NOTICE 'Erro ao conceder %: %', _permission, _result;
      END IF;

    EXCEPTION WHEN OTHERS THEN
      _error_count := _error_count + 1;
      RAISE NOTICE 'Erro ao conceder %: %', _permission, SQLERRM;
    END;
  END LOOP;

  RETURN format('Concedidas: %s permissões. Erros: %s', _success_count, _error_count);
END;
$function$

CREATE OR REPLACE FUNCTION public.grant_unit_permission(_user_email text, _unit_code text, _permission permission_type, _granted_by uuid DEFAULT auth.uid())
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _user_id UUID;
  _unit_id UUID;
BEGIN
  -- Check if caller is admin
  IF NOT has_role(_granted_by, 'admin'::app_role) THEN
    RETURN 'Erro: Apenas administradores podem conceder permissões';
  END IF;

  -- Find user by email
  SELECT id INTO _user_id 
  FROM auth.users 
  WHERE email = _user_email;

  IF _user_id IS NULL THEN
    RETURN 'Erro: Usuário não encontrado com email: ' || _user_email;
  END IF;

  -- Find unit by code
  SELECT id INTO _unit_id 
  FROM public.units 
  WHERE code = _unit_code;

  IF _unit_id IS NULL THEN
    RETURN 'Erro: Unidade não encontrada com código: ' || _unit_code;
  END IF;

  -- Insert or update permission
  INSERT INTO public.user_unit_permissions (user_id, unit_id, permission, granted_by)
  VALUES (_user_id, _unit_id, _permission, _granted_by)
  ON CONFLICT (user_id, unit_id, permission) 
  DO UPDATE SET 
    is_active = true,
    granted_by = _granted_by,
    granted_at = now(),
    updated_at = now();

  RETURN 'Permissão concedida com sucesso para: ' || _user_email || ' na unidade: ' || _unit_code;
END;
$function$

CREATE OR REPLACE FUNCTION public.guard_recent_payment_dashboard()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pag RECORD;
BEGIN
  IF NEW.matricula IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT data_pagamento, forma_pagamento, correlation_id
    INTO v_pag
  FROM pagamentos
  WHERE matricula = NEW.matricula
    AND COALESCE(reembolso_realizado, false) = false
    AND data_pagamento >= NOW() - interval '48 hours'
  ORDER BY data_pagamento DESC
  LIMIT 1;

  IF FOUND THEN
    NEW.pagamento_feito := true;
    NEW.data_pagamento := v_pag.data_pagamento;
    NEW.plataforma_pagamento_utilizada := COALESCE(
      v_pag.forma_pagamento,
      NEW.plataforma_pagamento_utilizada
    );
    NEW.correlation_id := COALESCE(v_pag.correlation_id, NEW.correlation_id);
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.guard_recent_payment_setembro()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pag RECORD;
BEGIN
  IF NEW.matricula IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT data_pagamento, forma_pagamento
    INTO v_pag
  FROM pagamentos
  WHERE matricula = NEW.matricula
    AND COALESCE(reembolso_realizado, false) = false
    AND data_pagamento >= NOW() - interval '48 hours'
  ORDER BY data_pagamento DESC
  LIMIT 1;

  IF FOUND THEN
    NEW.pagamento_feito := true;
    NEW.data_pagamento := v_pag.data_pagamento;
    NEW.plataforma_pagamento_utilizada := COALESCE(
      v_pag.forma_pagamento,
      NEW.plataforma_pagamento_utilizada
    );
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  user_role app_role := 'user';
BEGIN
  -- Check if this is an admin email
  IF NEW.email IN ('victor@7bee.com', 'andre@7bee.com') THEN
    user_role := 'admin';
  END IF;

  -- Insert profile without default unit
  INSERT INTO public.profiles (user_id, name)
  VALUES (
    NEW.id, 
    COALESCE(NEW.raw_user_meta_data->>'name', split_part(NEW.email, '@', 1))
  );

  -- Assign role
  INSERT INTO public.user_roles (user_id, role)
  VALUES (NEW.id, user_role);

  -- If admin, grant admin permission to all units
  IF user_role = 'admin' THEN
    INSERT INTO public.user_unit_permissions (user_id, unit_id, permission)
    SELECT NEW.id, u.id, 'admin'::permission_type
    FROM public.units u;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.isa_registrar_opt_out(p_phone text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_norm text := norm_phone_br(p_phone);
  v_n int;
begin
  if v_norm is null or length(v_norm) < 12 then
    return jsonb_build_object('success', false, 'reason', 'telefone_invalido', 'phone_norm', v_norm);
  end if;

  update adimplentes_base
     set relacionamento_opt_out = true,
         updated_at = now()
   where norm_phone_br(telefone) = v_norm
     and bi_atual;

  get diagnostics v_n = row_count;
  return jsonb_build_object('success', true, 'updated', v_n, 'phone_norm', v_norm);
end;
$function$

CREATE OR REPLACE FUNCTION public.log_event(p_actor_type text, p_actor_id text, p_actor_name text DEFAULT NULL::text, p_actor_url text DEFAULT NULL::text, p_event_type text DEFAULT NULL::text, p_entity_type text DEFAULT NULL::text, p_entity_id text DEFAULT NULL::text, p_source_system text DEFAULT 'app'::text, p_source_detail text DEFAULT NULL::text, p_correlation_id text DEFAULT NULL::text, p_parent_event_id bigint DEFAULT NULL::bigint, p_unit_id uuid DEFAULT NULL::uuid, p_cliente_id bigint DEFAULT NULL::bigint, p_before_data jsonb DEFAULT NULL::jsonb, p_after_data jsonb DEFAULT NULL::jsonb, p_metadata jsonb DEFAULT NULL::jsonb)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_id BIGINT;
BEGIN
  IF p_actor_type NOT IN ('HUMAN','AUTOMATION','SYSTEM','EXTERNAL') THEN
    RAISE EXCEPTION 'log_event: actor_type inválido (%). Aceitos: HUMAN, AUTOMATION, SYSTEM, EXTERNAL.', p_actor_type;
  END IF;

  INSERT INTO event_log (
    actor_type, actor_id, actor_name, actor_url,
    event_type, entity_type, entity_id,
    source_system, source_detail, correlation_id, parent_event_id,
    unit_id, cliente_id, before_data, after_data, metadata
  ) VALUES (
    p_actor_type, p_actor_id, p_actor_name, p_actor_url,
    p_event_type, p_entity_type, p_entity_id,
    p_source_system, p_source_detail, p_correlation_id, p_parent_event_id,
    p_unit_id, p_cliente_id, p_before_data, p_after_data, p_metadata
  ) RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.mark_refund_by_correlation(p_correlation_id text, p_motivo text, p_realizado_by uuid DEFAULT NULL::uuid, p_source text DEFAULT 'manual'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_pagamento_id bigint;
  v_already_refunded boolean := false;
  v_motivo_final text;
BEGIN
  v_motivo_final := COALESCE(p_motivo, 'Estorno via ' || p_source);

  SELECT id, reembolso_realizado
    INTO v_pagamento_id, v_already_refunded
  FROM pagamentos
  WHERE correlation_id = p_correlation_id
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_pagamento_id IS NULL THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'pagamento_not_found',
      'correlation_id', p_correlation_id
    );
  END IF;

  IF v_already_refunded THEN
    RETURN jsonb_build_object(
      'ok', true,
      'already_refunded', true,
      'pagamento_id', v_pagamento_id
    );
  END IF;

  UPDATE pagamentos
     SET reembolso_realizado = true,
         reembolso_realizado_at = NOW(),
         reembolso_motivo = v_motivo_final,
         reembolso_realizado_by = p_realizado_by
   WHERE id = v_pagamento_id;

  UPDATE clientes_cobranca_dashboard
     SET reembolso_realizado = true,
         reembolso_realizado_at = NOW(),
         reembolso_motivo = v_motivo_final,
         reembolso_realizado_by = p_realizado_by
   WHERE correlation_id = p_correlation_id;

  RETURN jsonb_build_object(
    'ok', true,
    'already_refunded', false,
    'pagamento_id', v_pagamento_id,
    'source', p_source
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.motor_v2_build_components(p_components jsonb, p_nome text, p_valor text, p_matricula text, p_link text)
 RETURNS jsonb
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
declare
  comp jsonb; outp jsonb := '[]'::jsonb; b jsonb;
  body_text text; segs text[]; nvars int; params jsonb; pre text; val text; k int; i int;
begin
  for comp in select * from jsonb_array_elements(coalesce(p_components,'[]'::jsonb)) loop
    if comp->>'type'='HEADER' and comp->>'format'='TEXT' and coalesce(comp->>'text','') ~ '\{\{\d+\}\}' then
      outp := outp || jsonb_build_array(jsonb_build_object(
        'type','header','parameters',
        jsonb_build_array(jsonb_build_object('type','text','text',p_nome))));
    elsif comp->>'type'='BODY' then
      body_text := coalesce(comp->>'text','');
      nvars := (select count(*) from regexp_matches(body_text,'\{\{\d+\}\}','g'));
      if nvars > 0 then
        segs := regexp_split_to_array(body_text,'\{\{\d+\}\}');
        params := '[]'::jsonb;
        for k in 1..nvars loop
          pre := coalesce(segs[k],'');
          if pre ~ 'R\$\s*$' then val := p_valor;
          elsif pre ~* 'matr[ií]cula' then val := p_matricula;
          else val := p_nome; end if;
          params := params || jsonb_build_array(jsonb_build_object('type','text','text',val));
        end loop;
        outp := outp || jsonb_build_array(jsonb_build_object('type','body','parameters',params));
      end if;
    elsif comp->>'type'='BUTTONS' then
      i := 0;
      for b in select * from jsonb_array_elements(comp->'buttons') loop
        if b->>'type'='URL' and coalesce(b->>'url','') ~ '\{\{\d+\}\}' then
          outp := outp || jsonb_build_array(jsonb_build_object(
            'type','button','sub_type','url','index',i::text,
            'parameters',jsonb_build_array(jsonb_build_object('type','text','text',p_link))));
        end if;
        i := i + 1;
      end loop;
    end if;
  end loop;
  return outp;
end $function$

CREATE OR REPLACE FUNCTION public.motor_v2_invoke_edge(p_function_name text, p_body jsonb DEFAULT '{}'::jsonb)
 RETURNS bigint
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_api_key TEXT;
  v_url     TEXT;
  v_req_id  BIGINT;
BEGIN
  -- Lê API key do vault
  SELECT decrypted_secret INTO v_api_key
  FROM vault.decrypted_secrets
  WHERE name = 'motor_v2_api_key'
  LIMIT 1;

  IF v_api_key IS NULL THEN
    RAISE EXCEPTION 'motor_v2_invoke_edge: secret motor_v2_api_key não encontrado no vault';
  END IF;

  v_url := 'https://ubwcxktaruxqacxltovq.supabase.co/functions/v1/' || p_function_name;

  SELECT net.http_post(
    url := v_url,
    body := p_body,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-api-key', v_api_key
    ),
    timeout_milliseconds := 60000
  ) INTO v_req_id;

  -- Log no event_log pra rastrear invocações
  INSERT INTO event_log (
    actor_type, actor_id, actor_name,
    event_type, source_system, source_detail,
    metadata
  ) VALUES (
    'AUTOMATION', 'pg_cron', 'pg_cron job',
    'EDGE_FUNCTION_INVOCADA', 'pg_cron',
    p_function_name,
    jsonb_build_object(
      'function', p_function_name,
      'body', p_body,
      'request_id', v_req_id,
      'invoked_at', now()
    )
  );

  RETURN v_req_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.motor_v2_pick_template(p_waba_id text, p_regua text, p_dia_ciclo integer, p_nonce text)
 RETURNS TABLE(template_name text, meta_template_id text, pool_used text, dia_resolvido integer)
 LANGUAGE plpgsql
AS $function$
declare v_regua text := lower(p_regua); v_pool text; v_dia int;
begin
  if p_dia_ciclo is null then
    v_pool := v_regua || '_sabado';
    return query
      select ti.template_name, ti.meta_template_id, v_pool, null::int
      from template_inventory ti
      where ti.waba_id=p_waba_id and ti.status='APPROVED' and ti.category='UTILITY'
        and ti.paused_by_sentinel=false
        and ti.template_name ~ ('^'||v_regua||'_sabado_v[0-9]')
      order by md5(coalesce(p_nonce,'')||random()::text) limit 1;
    return;
  end if;
  select max(d.dia) into v_dia from (
    select ((regexp_match(ti.template_name,'^'||v_regua||'_dia([0-9]+)_v[0-9]'))[1])::int as dia
    from template_inventory ti
    where ti.waba_id=p_waba_id and ti.status='APPROVED' and ti.category='UTILITY'
      and ti.paused_by_sentinel=false
      and ti.template_name ~ ('^'||v_regua||'_dia[0-9]+_v[0-9]')
  ) d where d.dia is not null and d.dia <= p_dia_ciclo;
  if v_dia is null then return; end if;
  v_pool := v_regua||'_dia'||v_dia;
  return query
    select ti.template_name, ti.meta_template_id, v_pool, v_dia
    from template_inventory ti
    where ti.waba_id=p_waba_id and ti.status='APPROVED' and ti.category='UTILITY'
      and ti.paused_by_sentinel=false
      and ti.template_name ~ ('^'||v_regua||'_dia'||v_dia||'_v[0-9]')
    order by md5(coalesce(p_nonce,'')||random()::text) limit 1;
end;
$function$

CREATE OR REPLACE FUNCTION public.notify_orphan_payment_created()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_internal_key text;
  v_supabase_url text;
  v_function_url text;
  v_payload jsonb;
BEGIN
  -- Pega chave interna da config
  SELECT value INTO v_internal_key
  FROM public.app_internal_config
  WHERE key = 'NOTIFY_ORPHAN_INTERNAL_KEY';

  IF v_internal_key IS NULL THEN
    RAISE WARNING 'NOTIFY_ORPHAN_INTERNAL_KEY não está em app_internal_config — pulando email';
    RETURN NEW;
  END IF;

  -- URL da edge function (hardcoded para nosso projeto)
  v_function_url := 'https://ubwcxktaruxqacxltovq.supabase.co/functions/v1/notify-orphan-email';

  v_payload := jsonb_build_object(
    'orfao_id', NEW.id,
    'source', NEW.source,
    'gateway_correlation_id', NEW.gateway_correlation_id,
    'valor', NEW.valor,
    'data_pagamento', NEW.data_pagamento,
    'payer_name', NEW.payer_name,
    'payer_phone', NEW.payer_phone
  );

  -- Chamada HTTP assíncrona (não bloqueia o INSERT)
  PERFORM net.http_post(
    url := v_function_url,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'x-internal-key', v_internal_key
    ),
    body := v_payload,
    timeout_milliseconds := 10000
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Email é best-effort. Falha aqui NÃO deve impedir gravação do órfão.
  RAISE WARNING 'notify_orphan_payment_created falhou: %', SQLERRM;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.reconcile_orfao(p_orfao_id bigint, p_matricula text, p_realizado_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_orfao public.pagamentos_orfaos%ROWTYPE;
  v_unit_id uuid;
  v_name text;
  v_whatsapp text;
  v_regua text;
  v_forma text;
  v_register_result jsonb;
  v_pagamento_id bigint;
BEGIN
  SELECT * INTO v_orfao FROM pagamentos_orfaos WHERE id = p_orfao_id;
  IF v_orfao.id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'orfao_not_found');
  END IF;

  IF v_orfao.reconciliado THEN
    RETURN jsonb_build_object('ok', false, 'error', 'orfao_ja_reconciliado',
                              'pagamento_id', v_orfao.pagamento_id);
  END IF;

  SELECT unit_id, name, whatsapp, regua
    INTO v_unit_id, v_name, v_whatsapp, v_regua
  FROM clientes_cobranca_dashboard
  WHERE matricula = p_matricula
  LIMIT 1;

  IF v_unit_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'matricula_sem_unit_id',
                              'matricula', p_matricula);
  END IF;

  -- Normalização do forma_pagamento: PIX gateways (woovi/abacate) → 'pix'.
  -- Stripe e demais mantêm o source original.
  v_forma := CASE
    WHEN v_orfao.source IN ('woovi', 'abacate') THEN 'pix'
    ELSE v_orfao.source
  END;

  v_register_result := public.register_payment(
    p_correlation_id := v_orfao.gateway_correlation_id,
    p_matricula      := p_matricula,
    p_name           := COALESCE(v_name, v_orfao.payer_name),
    p_whatsapp       := COALESCE(v_whatsapp, v_orfao.payer_phone, ''),
    p_valor          := v_orfao.valor,
    p_data_pagamento := v_orfao.data_pagamento,
    p_regua          := v_regua,
    p_forma          := v_forma,
    p_comprovante    := NULL,
    p_unit_id        := v_unit_id,
    p_gateway_charge_id := v_orfao.gateway_charge_id
  );

  v_pagamento_id := (v_register_result->>'pagamento_id')::bigint;

  UPDATE pagamentos_orfaos
     SET reconciliado = true,
         reconciliado_at = NOW(),
         reconciliado_by = p_realizado_by,
         matricula_reconciliada = p_matricula,
         pagamento_id = v_pagamento_id,
         updated_at = NOW()
   WHERE id = p_orfao_id;

  RETURN jsonb_build_object(
    'ok', true,
    'orfao_id', p_orfao_id,
    'pagamento_id', v_pagamento_id,
    'forma_pagamento', v_forma,
    'register_result', v_register_result
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.record_inbound_message(p_phone_number_id text, p_message jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_wamid     TEXT;
  v_from      TEXT;
  v_type      TEXT;
  v_body      TEXT;
  v_ts        TIMESTAMPTZ;
  v_unit_id   UUID;
  v_optout    BOOLEAN := false;
  v_id        BIGINT;
BEGIN
  v_wamid := p_message->>'id';
  v_from  := p_message->>'from';
  v_type  := p_message->>'type';

  v_ts := COALESCE(
    CASE WHEN p_message->>'timestamp' ~ '^\d+$'
         THEN to_timestamp((p_message->>'timestamp')::bigint) END,
    now()
  );

  -- Corpo textual por tipo de mensagem
  v_body := COALESCE(
    p_message->'text'->>'body',
    p_message->'button'->>'text',
    p_message->'interactive'->'button_reply'->>'title',
    p_message->'interactive'->'list_reply'->>'title',
    p_message->'reaction'->>'emoji',
    p_message->'image'->>'caption',
    p_message->'video'->>'caption',
    p_message->'document'->>'caption'
  );

  -- Deteccao de opt-out (palavra inteira, case-insensitive)
  IF v_body IS NOT NULL
     AND upper(v_body) ~ '\m(SAIR|PARE|PARAR|STOP|CANCELAR|DESCADASTRAR)\M' THEN
    v_optout := true;
  END IF;

  v_unit_id := (SELECT unit_id FROM disparadores_whatsapp
                WHERE numero_telefone = p_phone_number_id LIMIT 1);

  INSERT INTO message_inbound(
    wamid, from_phone, phone_number_id, unit_id, type, body,
    is_optout, received_at, raw_value
  )
  VALUES (
    v_wamid, v_from, p_phone_number_id, v_unit_id, v_type, v_body,
    v_optout, v_ts, p_message
  )
  ON CONFLICT (wamid) DO NOTHING
  RETURNING id INTO v_id;

  RETURN jsonb_build_object(
    'ok', true,
    'id', v_id,
    'deduped', v_id IS NULL,
    'is_optout', v_optout,
    'unit_id', v_unit_id
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.record_meta_account_event(p_waba_id text, p_field text, p_value jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_phone_id      TEXT;
  v_quality       TEXT;
  v_name_status   TEXT;
  v_event         TEXT;
  v_limit         TEXT;
  v_event_id      BIGINT;
  v_health_id     BIGINT;
  v_violation_id  BIGINT;
  v_capability_id BIGINT;
  v_unit_id       UUID;
  v_severity      TEXT := 'info';
BEGIN
  -- Extrai phone_number_id quando aplicavel
  v_phone_id := COALESCE(
    p_value->>'phone_number_id',
    p_value->>'display_phone_number',
    p_value->>'phone_number'
  );

  -- unit_id pela WABA (fallback: pelo phone)
  v_unit_id := COALESCE(
    (SELECT unit_id FROM disparadores_whatsapp WHERE waba_id = p_waba_id LIMIT 1),
    (SELECT unit_id FROM disparadores_whatsapp WHERE numero_telefone = v_phone_id LIMIT 1)
  );

  -- Severidade pra observabilidade. Vocabulario: info < low < medium < high.
  -- account_update (violacao/restricao/ban) usa 'high' de proposito — fica
  -- dentro do vocabulario existente, sem risco de filtro downstream perder.
  IF p_field = 'account_update' THEN
    v_severity := 'high';   -- violacao / restricao / ban da WABA
  ELSIF p_field = 'account_review_update' THEN
    v_severity := 'high';
  ELSIF p_field = 'phone_number_quality_update'
        AND COALESCE(p_value->>'new_quality_score', p_value->>'event') IN ('RED', 'FLAGGED') THEN
    v_severity := 'high';
  ELSIF p_field IN ('account_alerts', 'security') THEN
    v_severity := 'medium';
  ELSIF p_field = 'business_capability_update' THEN
    v_severity := 'low';
  END IF;

  -- 1) Log unificado (sempre) — acontece ANTES de qualquer extracao estruturada
  INSERT INTO webhook_events_log(source, event_type, correlation_id, payload, processed, error)
  VALUES (
    'meta',
    p_field,
    COALESCE(v_phone_id, p_waba_id),
    p_value || jsonb_build_object('_waba_id', p_waba_id, '_severity', v_severity),
    true,
    NULL
  )
  RETURNING id INTO v_event_id;

  -- 2) phone_health snapshot (quality / name)
  IF p_field IN ('phone_number_quality_update', 'phone_number_name_update') AND v_phone_id IS NOT NULL THEN
    v_quality     := p_value->>'new_quality_score';
    v_name_status := p_value->>'decision';
    v_event       := p_value->>'event';
    v_limit       := COALESCE(p_value->>'current_limit', p_value->>'messaging_limit_tier');

    INSERT INTO phone_health(
      phone_number_id, unit_id, quality_rating, status, name_status,
      event, current_limit, raw_response
    )
    SELECT
      v_phone_id,
      v_unit_id,
      v_quality,
      NULL,    -- status (CONNECTED/BANNED) so via Graph API polling
      v_name_status,
      v_event,
      v_limit,
      p_value || jsonb_build_object('_event_source', p_field, '_waba_id', p_waba_id)
    RETURNING id INTO v_health_id;
  END IF;

  -- 3) account_update -> waba_violations (bloco protegido: log nunca e perdido)
  IF p_field = 'account_update' THEN
    BEGIN
      INSERT INTO waba_violations(
        waba_id, unit_id, event, violation_type, restriction_type,
        restriction_expires_at, ban_state, affected_phone_number,
        raw_value, webhook_event_id
      )
      VALUES (
        p_waba_id,
        v_unit_id,
        p_value->>'event',
        COALESCE(p_value->'violation_info'->>'violation_type', p_value->>'violation_type'),
        p_value->'restriction_info'->0->>'restriction_type',
        CASE
          WHEN p_value->'restriction_info'->0->>'expiration' ~ '^\d+$'
            THEN to_timestamp((p_value->'restriction_info'->0->>'expiration')::bigint)
          WHEN p_value->'restriction_info'->0->>'expiration' ~ '\d{4}-\d{2}-\d{2}'
            THEN (p_value->'restriction_info'->0->>'expiration')::timestamptz
          ELSE NULL
        END,
        COALESCE(p_value->'ban_info'->>'waba_ban_state',
                 p_value->'ban_info'->>'ban_state',
                 p_value->>'ban_state'),
        COALESCE(p_value->>'phone_number', v_phone_id),
        p_value,
        v_event_id
      )
      RETURNING id INTO v_violation_id;
    EXCEPTION WHEN OTHERS THEN
      v_violation_id := NULL;
    END;
  END IF;

  -- 4) business_capability_update -> waba_capability (bloco protegido)
  IF p_field = 'business_capability_update' THEN
    BEGIN
      INSERT INTO waba_capability(
        waba_id, unit_id, max_phone_numbers, max_daily_conversations,
        raw_value, webhook_event_id
      )
      VALUES (
        p_waba_id,
        v_unit_id,
        CASE WHEN COALESCE(p_value->>'max_phone_numbers_per_waba',
                           p_value->>'max_phone_numbers_per_business') ~ '^\d+$'
             THEN COALESCE(p_value->>'max_phone_numbers_per_waba',
                           p_value->>'max_phone_numbers_per_business')::int END,
        CASE WHEN p_value->>'max_daily_conversation_per_phone' ~ '^\d+$'
             THEN (p_value->>'max_daily_conversation_per_phone')::int END,
        p_value,
        v_event_id
      )
      RETURNING id INTO v_capability_id;
    EXCEPTION WHEN OTHERS THEN
      v_capability_id := NULL;
    END;
  END IF;

  RETURN jsonb_build_object(
    'ok', true,
    'event_id', v_event_id,
    'phone_health_id', v_health_id,
    'violation_id', v_violation_id,
    'capability_id', v_capability_id,
    'severity', v_severity,
    'phone_id', v_phone_id,
    'unit_id', v_unit_id
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.resolve_orfao_matricula(p_correlation_id text, p_payer_phone text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_matricula text;
  v_unit_id uuid;
BEGIN
  -- Estratégia 1: link match (mais confiável)
  SELECT matricula, unit_id INTO v_matricula, v_unit_id
  FROM links_pagamentos_gerados
  WHERE correlation_id = p_correlation_id
  LIMIT 1;

  IF v_matricula IS NOT NULL THEN
    RETURN jsonb_build_object(
      'ok', true,
      'matricula', v_matricula,
      'unit_id', v_unit_id,
      'via', 'links'
    );
  END IF;

  -- Estratégia 2: phone match (apenas se telefone informado)
  IF p_payer_phone IS NULL OR p_payer_phone = '' THEN
    RETURN jsonb_build_object('ok', false, 'error', 'no_match', 'reason', 'no_phone');
  END IF;

  SELECT matricula, unit_id INTO v_matricula, v_unit_id
  FROM clientes_cobranca_dashboard
  WHERE regexp_replace(whatsapp, '\D', '', 'g')
      = regexp_replace(p_payer_phone, '\D', '', 'g')
  LIMIT 1;

  IF v_matricula IS NOT NULL THEN
    RETURN jsonb_build_object(
      'ok', true,
      'matricula', v_matricula,
      'unit_id', v_unit_id,
      'via', 'phone'
    );
  END IF;

  RETURN jsonb_build_object('ok', false, 'error', 'no_match');
END;
$function$

CREATE OR REPLACE FUNCTION public.revoke_unit_permission(_user_email text, _unit_code text, _permission permission_type)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _user_id UUID;
  _unit_id UUID;
BEGIN
  -- Check if caller is admin
  IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
    RETURN 'Erro: Apenas administradores podem revogar permissões';
  END IF;

  -- Find user by email
  SELECT id INTO _user_id FROM auth.users WHERE email = _user_email;
  IF _user_id IS NULL THEN
    RETURN 'Erro: Usuário não encontrado';
  END IF;

  -- Find unit by code
  SELECT id INTO _unit_id FROM public.units WHERE code = _unit_code;
  IF _unit_id IS NULL THEN
    RETURN 'Erro: Unidade não encontrada';
  END IF;

  -- Deactivate permission
  UPDATE public.user_unit_permissions 
  SET is_active = false, updated_at = now()
  WHERE user_id = _user_id 
    AND unit_id = _unit_id 
    AND permission = _permission;

  RETURN 'Permissão revogada com sucesso';
END;
$function$

CREATE OR REPLACE FUNCTION public.rollback_sync(p_sync_log_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
 SET statement_timeout TO '180s'
AS $function$
declare
  v_unit_id uuid;
  v_date    date;
  v_live    integer := 0;
  v_dash    integer := 0;
begin
  select unit_id, snapshot_date into v_unit_id, v_date
  from public.cobranca_sync_backup
  where sync_log_id = p_sync_log_id
  limit 1;

  if v_unit_id is null then
    return jsonb_build_object('ok', false,
      'erro', 'Sem foto de backup para sync_log_id ' || p_sync_log_id);
  end if;

  perform pg_advisory_xact_lock(hashtext('sync_cobranca'), hashtext(v_unit_id::text));

  delete from public.clientes_cobranca_setembro
  where unit_id = v_unit_id
     or matricula in (select row_data->>'matricula' from public.cobranca_sync_backup
                      where sync_log_id = p_sync_log_id and source_table = 'clientes_cobranca_setembro');
  insert into public.clientes_cobranca_setembro
  select (jsonb_populate_record(null::public.clientes_cobranca_setembro, row_data)).*
  from public.cobranca_sync_backup
  where sync_log_id = p_sync_log_id and source_table = 'clientes_cobranca_setembro';
  get diagnostics v_live = row_count;

  delete from public.clientes_cobranca_dashboard
  where unit_id = v_unit_id
     or matricula in (select row_data->>'matricula' from public.cobranca_sync_backup
                      where sync_log_id = p_sync_log_id and source_table = 'clientes_cobranca_dashboard');
  insert into public.clientes_cobranca_dashboard
  select (jsonb_populate_record(null::public.clientes_cobranca_dashboard, row_data)).*
  from public.cobranca_sync_backup
  where sync_log_id = p_sync_log_id and source_table = 'clientes_cobranca_dashboard';
  get diagnostics v_dash = row_count;

  delete from public.cobranca_clientes_removidos where sync_log_id = p_sync_log_id;
  delete from public.sync_snapshots             where sync_log_id = p_sync_log_id;

  return jsonb_build_object(
    'ok', true,
    'sync_log_id', p_sync_log_id,
    'unit_id', v_unit_id,
    'snapshot_date', v_date,
    'restaurados_lista_viva', v_live,
    'restaurados_dashboard', v_dash);
end;
$function$

CREATE OR REPLACE FUNCTION public.route_inbound(p_phone text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_norm text := norm_phone_br(p_phone);
  v_unit uuid;
  v_matricula text;
  v_nome text;
  v_queue text;
begin
  if v_norm is null or length(v_norm) < 12 then
    return jsonb_build_object('rail', 'none', 'reason', 'telefone_invalido', 'phone_norm', v_norm);
  end if;

  -- 1. Cobrança em aberto vence. Se houver mais de um (família no mesmo número),
  --    pega o de maior valor em aberto.
  select c.unit_id, c.matricula, c.name
    into v_unit, v_matricula, v_nome
  from clientes_cobranca_setembro c
  where norm_phone_br(c.whatsapp) = v_norm
    and coalesce(c.pagamento_feito, false) = false
  order by c.valor_inadimplente desc nulls last, c.updated_at desc nulls last
  limit 1;

  if found then
    select u.rabbitmq_queue into v_queue from units u where u.id = v_unit;
    return jsonb_build_object(
      'rail', 'cobranca',
      'unit_id', v_unit,
      'matricula', v_matricula,
      'nome', v_nome,
      'queue', v_queue,
      'phone_norm', v_norm
    );
  end if;

  -- 2. Filiado ativo => relacionamento.
  select a.unit_id, a.matricula, a.nome
    into v_unit, v_matricula, v_nome
  from adimplentes_base a
  where norm_phone_br(a.telefone) = v_norm
    and a.bi_atual
  order by a.updated_at desc nulls last
  limit 1;

  if found then
    select u.rabbitmq_queue into v_queue from units u where u.id = v_unit;
    return jsonb_build_object(
      'rail', 'relacionamento',
      'unit_id', v_unit,
      'matricula', v_matricula,
      'nome', v_nome,
      'queue', case when v_queue is null then null else v_queue || '-relacionamento' end,
      'phone_norm', v_norm
    );
  end if;

  -- 3. Em nenhuma das listas => descarta (comportamento atual).
  return jsonb_build_object('rail', 'none', 'reason', 'nao_encontrado', 'phone_norm', v_norm);
end;
$function$

CREATE OR REPLACE FUNCTION public.sentinel_apply_meta_event(p_waba_id text, p_template_name text, p_event_field text, p_event_value jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row template_inventory%ROWTYPE;
  v_new_status         TEXT;
  v_new_quality        TEXT;
  v_new_category       TEXT;
  v_previous_category  TEXT;
  v_detected_category  TEXT;
  v_current_category   TEXT;
  v_rejection_reason   TEXT;
  v_is_critical        BOOLEAN := false;
  v_critical_reason    TEXT;
  v_event_record       JSONB;
  v_chain_depth        INT;
  v_root_id            BIGINT;
  v_loop_aborted       BOOLEAN := false;
BEGIN
  SELECT * INTO v_row FROM template_inventory
   WHERE template_name = p_template_name AND waba_id = p_waba_id LIMIT 1;
  IF NOT FOUND THEN
    INSERT INTO template_inventory(template_name, waba_id, last_checked_at)
    VALUES (p_template_name, p_waba_id, now()) RETURNING * INTO v_row;
  END IF;

  -- Extrai campos do evento
  IF p_event_field = 'message_template_status_update' THEN
    v_new_status := p_event_value->>'event';
    IF v_new_status = 'REJECTED' THEN
      v_rejection_reason := NULLIF(p_event_value->>'reason', 'NONE');
    END IF;
  ELSIF p_event_field = 'message_template_quality_update' THEN
    v_new_quality := p_event_value->>'new_quality_score';
  ELSIF p_event_field = 'template_category_update' THEN
    v_new_category      := p_event_value->>'new_category';
    v_previous_category := p_event_value->>'previous_category';
  ELSIF p_event_field = 'template_correct_category_detection' THEN
    v_detected_category := COALESCE(p_event_value->>'correct_category', p_event_value->>'detected_category');
    v_current_category  := COALESCE(p_event_value->>'current_category', v_row.category);
  END IF;

  -- Decide critical
  IF v_new_status IN ('REJECTED', 'PAUSED', 'DISABLED', 'FLAGGED') THEN
    v_is_critical := true;
    v_critical_reason := 'status=' || v_new_status;
  ELSIF v_new_quality = 'RED' THEN
    v_is_critical := true;
    v_critical_reason := 'quality=RED';
  ELSIF v_new_category = 'MARKETING' AND v_previous_category = 'UTILITY' THEN
    v_is_critical := true;
    v_critical_reason := 'category UTILITY->MARKETING';
  ELSIF v_detected_category = 'MARKETING' AND COALESCE(v_current_category, 'UTILITY') = 'UTILITY' THEN
    v_is_critical := true;
    v_critical_reason := 'preventive: meta detected MARKETING (correct_category_detection)';
  END IF;

  -- ====== GUARDRAIL ANTI-LOOP ======
  -- Se esse evento é crítico E esse template já é uma variação (sentinel_generation > 0),
  -- conta quantas gerações tem a chain inteira até a raiz. Se >= 3, ABORTA o is_critical.
  IF v_is_critical AND COALESCE(v_row.sentinel_generation, 0) > 0 THEN
    -- Sobe a chain até a raiz pra contar profundidade efetiva
    WITH RECURSIVE chain AS (
      SELECT id, parent_template_inventory_id, sentinel_generation
        FROM template_inventory WHERE id = v_row.id
      UNION ALL
      SELECT t.id, t.parent_template_inventory_id, t.sentinel_generation
        FROM template_inventory t JOIN chain c ON c.parent_template_inventory_id = t.id
    )
    SELECT MAX(sentinel_generation), MIN(id) FILTER (WHERE sentinel_generation = 0)
      INTO v_chain_depth, v_root_id FROM chain;

    IF COALESCE(v_chain_depth, 0) >= 3 THEN
      v_is_critical := false;
      v_loop_aborted := true;
      v_critical_reason := 'loop_aborted: chain_depth=' || v_chain_depth || ' (max=3); manual intervention required';
    END IF;
  END IF;

  v_event_record := jsonb_build_object(
    'received_at', now(),
    'field', p_event_field,
    'value', p_event_value,
    'is_critical', v_is_critical,
    'critical_reason', v_critical_reason,
    'loop_aborted', v_loop_aborted
  );

  UPDATE template_inventory
     SET status           = COALESCE(v_new_status, status),
         quality_score    = COALESCE(v_new_quality, quality_score),
         category         = COALESCE(v_new_category, category),
         rejection_reason = COALESCE(v_rejection_reason, rejection_reason),
         last_checked_at  = now(),
         updated_at       = now(),
         meta_event_history = COALESCE(meta_event_history, '[]'::jsonb) || v_event_record,
         paused_by_sentinel = CASE WHEN v_is_critical OR v_loop_aborted THEN true ELSE paused_by_sentinel END,
         paused_at        = CASE WHEN (v_is_critical OR v_loop_aborted) AND paused_at IS NULL THEN now() ELSE paused_at END,
         paused_reason    = CASE WHEN v_is_critical OR v_loop_aborted THEN v_critical_reason ELSE paused_reason END,
         is_active_in_cadence = CASE WHEN v_is_critical OR v_loop_aborted THEN false ELSE is_active_in_cadence END
   WHERE id = v_row.id;

  RETURN jsonb_build_object(
    'ok', true,
    'template_inventory_id', v_row.id,
    'template_name', p_template_name,
    'waba_id', p_waba_id,
    'is_critical', v_is_critical,
    'loop_aborted', v_loop_aborted,
    'critical_reason', v_critical_reason,
    'rejection_reason', v_rejection_reason,
    'body_text', v_row.body_text,
    'category_after', COALESCE(v_new_category, v_row.category),
    'status_after', COALESCE(v_new_status, v_row.status),
    'quality_after', COALESCE(v_new_quality, v_row.quality_score)
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.set_user_tracking()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  NEW.updated_by = auth.uid();
  NEW.updated_at = now();

  -- Set created_by only on insert
  IF TG_OP = 'INSERT' THEN
    NEW.created_by = auth.uid();
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_log_event_changes()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_actor_id       TEXT;
  v_actor_type     TEXT;
  v_actor_name     TEXT;
  v_actor_url      TEXT;
  v_source_detail  TEXT;
  v_event_type     TEXT;
  v_before         JSONB;
  v_after          JSONB;
  v_entity_id      TEXT;
  v_unit_id        UUID;
BEGIN
  -- Lê actor do session config; default SYSTEM se ausente.
  BEGIN
    v_actor_id := current_setting('app.actor_id', true);
  EXCEPTION WHEN OTHERS THEN v_actor_id := NULL;
  END;
  BEGIN
    v_actor_type := current_setting('app.actor_type', true);
  EXCEPTION WHEN OTHERS THEN v_actor_type := NULL;
  END;
  BEGIN
    v_actor_name := current_setting('app.actor_name', true);
  EXCEPTION WHEN OTHERS THEN v_actor_name := NULL;
  END;
  BEGIN
    v_actor_url := current_setting('app.actor_url', true);
  EXCEPTION WHEN OTHERS THEN v_actor_url := NULL;
  END;
  BEGIN
    v_source_detail := current_setting('app.source_detail', true);
  EXCEPTION WHEN OTHERS THEN v_source_detail := NULL;
  END;

  IF v_actor_id IS NULL OR v_actor_id = '' THEN
    v_actor_id := 'system';
  END IF;
  IF v_actor_type IS NULL OR v_actor_type = '' THEN
    v_actor_type := 'SYSTEM';
  END IF;
  IF v_source_detail IS NULL OR v_source_detail = '' THEN
    v_source_detail := TG_TABLE_NAME || ' (' || TG_NAME || ')';
  END IF;

  v_event_type := upper(TG_TABLE_NAME) || '_' || TG_OP;

  v_before := CASE TG_OP WHEN 'INSERT' THEN NULL ELSE to_jsonb(OLD) END;
  v_after  := CASE TG_OP WHEN 'DELETE' THEN NULL ELSE to_jsonb(NEW) END;

  -- entity_id: tenta 'id', senão usa 'unit_id'
  v_entity_id := COALESCE(
    (v_after->>'id'),
    (v_before->>'id'),
    (v_after->>'unit_id'),
    (v_before->>'unit_id')
  );

  -- unit_id: ambos before e after têm o mesmo na maioria dos casos
  BEGIN
    v_unit_id := COALESCE(
      (v_after->>'unit_id')::UUID,
      (v_before->>'unit_id')::UUID
    );
  EXCEPTION WHEN OTHERS THEN v_unit_id := NULL;
  END;

  INSERT INTO event_log (
    actor_type, actor_id, actor_name, actor_url,
    event_type, entity_type, entity_id,
    source_system, source_detail,
    before_data, after_data, unit_id
  ) VALUES (
    v_actor_type, v_actor_id, v_actor_name, v_actor_url,
    v_event_type, TG_TABLE_NAME, v_entity_id,
    'pg_trigger', v_source_detail,
    v_before, v_after, v_unit_id
  );

  RETURN COALESCE(NEW, OLD);
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_motor_v2_bloqueio_cliente()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_cancelled         INT;
  v_motivo            TEXT;
  v_motivo_detalhe    TEXT;
  v_cliente_cadencia  RECORD;
  v_pausou_agora      BOOLEAN := false;
BEGIN
  -- Detecta 2 transições que importam:
  --   (a) bloqueio_disparos: false → true
  --   (b) disparos_pausados_ate: NULL → futuro  OR  passado → futuro
  IF (NEW.bloqueio_disparos IS TRUE
      AND (OLD.bloqueio_disparos IS DISTINCT FROM TRUE)) THEN
    v_pausou_agora := true;
    v_motivo := 'BLOQUEIO_IA'; -- assume IA por default; humano via dashboard pode override depois
    v_motivo_detalhe := 'bloqueio_disparos virou true em ' || to_char(now(), 'YYYY-MM-DD HH24:MI:SS');
  ELSIF (NEW.disparos_pausados_ate IS NOT NULL
         AND NEW.disparos_pausados_ate > now()
         AND (OLD.disparos_pausados_ate IS DISTINCT FROM NEW.disparos_pausados_ate)) THEN
    v_pausou_agora := true;
    v_motivo := 'BLOQUEIO_IA';
    v_motivo_detalhe := 'disparos_pausados_ate setado pra ' || NEW.disparos_pausados_ate::text;
  END IF;

  IF NOT v_pausou_agora THEN
    RETURN NEW;
  END IF;

  -- 1. Cancela PROGRAMADAS futuras
  v_cancelled := motor_v2_cancel_future_disparos(NEW.matricula, NEW.unit_id, v_motivo);

  -- 2. Pausa cliente_cadencia (se existir ACTIVE ou PAUSED_REGUA_MORTA)
  UPDATE cliente_cadencia
  SET
    status        = 'PAUSED_BLOQUEADO',
    paused_at     = now(),
    paused_reason = v_motivo_detalhe,
    updated_at    = now()
  WHERE matricula = NEW.matricula
    AND unit_id   = NEW.unit_id
    AND status IN ('ACTIVE', 'PAUSED_REGUA_MORTA')
  RETURNING * INTO v_cliente_cadencia;

  -- 3. Insere fila_humana se ainda não está aberta
  IF v_cliente_cadencia.id IS NOT NULL THEN
    INSERT INTO fila_humana (
      unit_id, matricula, telefone, nome,
      cliente_cadencia_id, motivo, motivo_detalhe
    )
    SELECT
      NEW.unit_id, NEW.matricula, NEW.whatsapp, NEW.name,
      v_cliente_cadencia.id, v_motivo, v_motivo_detalhe
    WHERE NOT EXISTS (
      SELECT 1 FROM fila_humana
      WHERE matricula = NEW.matricula
        AND unit_id   = NEW.unit_id
        AND resolved_at IS NULL
    );
  END IF;

  -- 4. Loga
  INSERT INTO event_log (
    actor_type, actor_id, actor_name,
    event_type, entity_type, entity_id,
    source_system, source_detail,
    unit_id, cliente_id, metadata
  ) VALUES (
    'AUTOMATION', 'pg_trigger:bloqueio_cliente', 'Motor v2 bloqueio trigger',
    'CLIENTE_BLOQUEADO_IMEDIATO', 'cliente_cadencia',
    COALESCE(v_cliente_cadencia.id::text, NEW.matricula),
    'pg_trigger', 'clientes_cobranca_setembro AFTER UPDATE',
    NEW.unit_id, v_cliente_cadencia.id,
    jsonb_build_object(
      'matricula', NEW.matricula,
      'motivo', v_motivo,
      'motivo_detalhe', v_motivo_detalhe,
      'disparos_cancelados', v_cancelled
    )
  );

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.trg_motor_v2_recalc_gate_from_health()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_unit_id UUID;
BEGIN
  -- Tabelas têm coluna unit_id; se NULL, tentar derivar via phone_number_id
  -- ou waba_id (defensive).
  v_unit_id := NEW.unit_id;

  IF v_unit_id IS NULL THEN
    -- Sem unit_id no payload — não dá pra recalcular gate. Pula silenciosamente.
    RETURN NEW;
  END IF;

  -- Recalcula gate da unidade. Erros não derrubam o INSERT da fonte.
  BEGIN
    PERFORM motor_v2_recalc_gate(v_unit_id);
  EXCEPTION WHEN OTHERS THEN
    -- Loga no event_log e segue
    INSERT INTO event_log (
      actor_type, actor_id, event_type, source_system, source_detail,
      unit_id, metadata
    ) VALUES (
      'SYSTEM', 'pg_trigger',
      'GATE_RECALC_FALHOU', 'pg_trigger',
      TG_TABLE_NAME || '.' || TG_NAME,
      v_unit_id,
      jsonb_build_object('error', SQLERRM, 'sqlstate', SQLSTATE)
    );
  END;

  RETURN NEW;
END;
$function$

