$function$

CREATE OR REPLACE FUNCTION public.user_has_access_to_unit(unit_id_param uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  current_user_id UUID;
  is_admin BOOLEAN;
BEGIN
  -- Obter o ID do usuário autenticado
  current_user_id := auth.uid();

  -- Se não há usuário autenticado, negar acesso
  IF current_user_id IS NULL THEN
    RETURN FALSE;
  END IF;

  -- Verificar se o usuário é admin
  SELECT EXISTS (
    SELECT 1 
    FROM public.user_roles 
    WHERE user_id = current_user_id 
    AND role = 'admin'
  ) INTO is_admin;

  -- Se é admin, tem acesso a todas as unidades
  IF is_admin THEN
    RETURN TRUE;
  END IF;

  -- Para usuários não-admin, verificar se tem permissão na unidade específica
  -- Verificamos se existe qualquer permissão ativa para essa unidade
  RETURN EXISTS (
    SELECT 1
    FROM public.user_unit_permissions
    WHERE user_id = current_user_id
    AND unit_id = unit_id_param
    AND is_active = TRUE
  );
END;
$function$
